mapper.select:
SELECT shipper_id, SUM(ro.total_amount) amount
FROM t_receive_order_invoice  roi
left join t_receive_order ro on roi.receive_order_id = ro.receive_order_id
left join t_receive_order_waybill trow on trow.receive_order_id = ro.receive_order_id
where ro.make_invoice_flag = #{makeInvoiceFlag} and roi.invoice_status = #{invoiceStatus}
AND  ro.check_status != #{excludeCheckStatus}
and trow.waybill_id in

    #{item}

GROUP BY ro.shipper_id
